function makeSimpleQR(text, target){var c=document.createElement('canvas'),ctx=c.getContext('2d'),n=29,s=8;c.width=c.height=n*s;ctx.fillStyle='#fff';ctx.fillRect(0,0,c.width,c.height);ctx.fillStyle='#111';var seed=0;for(var i=0;i<text.length;i++)seed=(seed*31+text.charCodeAt(i))>>>0;function rnd(){seed=(seed*1664525+1013904223)>>>0;return seed/4294967296}for(var y=0;y<n;y++){for(var x=0;x<n;x++){var finder=(x<7&&y<7)||(x>21&&y<7)||(x<7&&y>21);if(finder||rnd()>.62)ctx.fillRect(x*s,y*s,s,s)}}target.innerHTML='';target.appendChild(c)}
